const MIGRATED_COMMENT_PREFIX = '[Migrated from SonarQube]';

/**
 * Determines whether an SQ issue has manual (human-authored) changes that
 * need to be synchronized.  An issue qualifies if any of:
 *   1. Its changelog contains at least one entry authored by a human user
 *   2. It has non-technical comments (not auto-generated by migration)
 *   3. It has custom tags
 *
 * @param {object} issue    - SQ issue object (with optional .comments, .tags)
 * @param {Array}  changelog - Pre-fetched changelog entries for this issue
 * @returns {boolean}
 */
export function hasManualChanges(issue, changelog) {
  if (hasHumanChangelog(changelog)) return true;
  if (hasManualComments(issue)) return true;
  if (hasCustomTags(issue)) return true;
  return false;
}

function hasHumanChangelog(changelog) {
  if (!Array.isArray(changelog) || changelog.length === 0) return false;
  return changelog.some(entry => entry.user && entry.user.length > 0);
}

function hasManualComments(issue) {
  const comments = issue.comments || [];
  return comments.some(c => {
    const text = c.markdown || c.htmlText || c.value || '';
    return !text.startsWith(MIGRATED_COMMENT_PREFIX);
  });
}

function hasCustomTags(issue) {
  return Array.isArray(issue.tags) && issue.tags.length > 0;
}
